//#region src/commands/init/utility/format.ts
const formatCode = async (code) => {
	return await format(code, { parser: "typescript" });
};

//#endregion
//#region src/commands/init/utility/imports.ts
/**
* Helper function to create an import object.
*/
const createImport = ({ name, alias, asType }) => {
	return {
		name,
		alias: alias ?? null,
		asType: asType ?? false
	};
};
/**
* Converts an import object to a string. This is specifically for the variables in the import.
* For the full import statement, use the `getImportString` function.
*/
const getImportVariableString = (import_) => {
	const alias = import_.alias ? ` as ${import_.alias}` : "";
	return `${import_.asType ? "type " : ""}${import_.name}${alias}`.trim();
};
/**
* Takes a collection of imports and returns a string of import statements.
*/
const getImportString = async (imports) => {
	const groupedImports = groupImports(imports);
	let importString = "";
	for (const { imports, path, isNamedImport } of groupedImports) {
		const vars = isNamedImport ? getImportVariableString(imports) : `{ ${imports.map(getImportVariableString).join(", ")} }`;
		importString += `import ${vars} from "${path}";\n`;
	}
	return (await formatCode(importString)).trim();
};
/**
* Takes a collection of imports and groups them by path.
*/
const groupImports = (imports) => {
	const result = [];
	for (const import_ of imports) {
		if (import_.isNamedImport) {
			result.push(import_);
			continue;
		}
		const existingIndex = result.findIndex((x) => x.path === import_.path && !x.isNamedImport);
		if (existingIndex !== -1) {
			result[existingIndex].imports.push(...import_.imports);
			continue;
		}
		result.push(import_);
	}
	return result.sort((a, b) => {
		if (a.isNamedImport && !b.isNamedImport) return 1;
		if (!a.isNamedImport && b.isNamedImport) return -1;
		return a.path.localeCompare(b.path);
	});
};

